import{_ as a,o as s,c as i,ag as t}from"./chunks/framework.B9unkguw.js";const c=JSON.parse('{"title":"İndirme ve Kurulum","description":"","frontmatter":{},"headers":[],"relativePath":"tr/qgc-user-guide/getting_started/download_and_install.md","filePath":"tr/qgc-user-guide/getting_started/download_and_install.md"}'),n={name:"tr/qgc-user-guide/getting_started/download_and_install.md"};function l(o,e,r,d,p,u){return s(),i("div",null,e[0]||(e[0]=[t(`<h1 id="indirme-ve-kurulum" tabindex="-1">İndirme ve Kurulum <a class="header-anchor" href="#indirme-ve-kurulum" aria-label="Permalink to &quot;İndirme ve Kurulum&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>These are <strong>daily build</strong> download links with the latest features. If you are looking for the last stable release, see the <a href="https://docs.qgroundcontrol.com/Stable_V5.0/en/qgc-user-guide/getting_started/download_and_install.html" target="_blank" rel="noreferrer">stable docs</a>.</p></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>See <a href="./../troubleshooting/qgc_setup.html">Troubleshooting QGC Setup</a> if <em>QGroundControl</em> doesn&#39;t start and run properly after installation!</p></div><h2 id="sistem-gereksinimleri" tabindex="-1">Sistem Gereksinimleri <a class="header-anchor" href="#sistem-gereksinimleri" aria-label="Permalink to &quot;Sistem Gereksinimleri&quot;">​</a></h2><p>QGC tüm güncel bilgisayar ya da mobil cihazlarda iyi bir şekilde çalışacaktır. taraf uygulamalara ve mevcut sistem kaynaklarına bağlıdır. Daha yüksek kapasiteli donanım daha iyi bir deneyim sunacaktır. En az 8 Gb Ram&#39;e, SSD&#39;ye, Nvidia ya da AMD ekran kartına ve i5 veya daha iyi bir işlemciye sahip bir bilgisayar çoğu uygulama için yeterince iyi olacaktır.</p><p>En iyi deneyim ve uyumluluk için size işletim sisteminizin en yeni sürümünü kullanmanızı öneriyoruz.</p><h2 id="windows" tabindex="-1">Windows <a class="header-anchor" href="#windows" aria-label="Permalink to &quot;Windows {#windows}&quot;">​</a></h2><p>Supported versions: Windows 10 (1809 or later), Windows 11:</p><ol><li>Download the installer: <ul><li><a href="https://d176tv9ibo4jno.cloudfront.net/builds/master/QGroundControl-installer-AMD64.exe" target="_blank" rel="noreferrer">x86_64</a></li><li><a href="https://d176tv9ibo4jno.cloudfront.net/builds/master/QGroundControl-installer-ARM64.exe" target="_blank" rel="noreferrer">Arm64</a></li></ul></li><li>exe&#39;ye çift tıklayın.</li></ol><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Windows kurulum programı 3 kısayol oluşturur: <strong>QGroundControl</strong>, <strong>GPU Compatibility Mode</strong>, <strong>GPU Safe Mode</strong>. Eğer başlatma veya video işleme sorunları yaşamıyorsanız ilk kısayolu kullanın. For more information see <a href="./../troubleshooting/qgc_setup.html#opengl_troubleshooting">Troubleshooting QGC Setup &gt; Windows: UI Rendering/Video Driver Issues</a>.</p></div><h2 id="macOS" tabindex="-1">Mac OS <a class="header-anchor" href="#macOS" aria-label="Permalink to &quot;Mac OS {#macOS}&quot;">​</a></h2><p>Supported versions: macOS 13 (Ventura) or later:</p><ol><li>Download <a href="https://d176tv9ibo4jno.cloudfront.net/builds/master/QGroundControl.dmg" target="_blank" rel="noreferrer">QGroundControl.dmg</a>.</li><li>.dmg dosyasına çift tıklayın, ardından çıkan ekranda <em>QGroundControl</em>&#39;ü <em>Application</em> dosyasına sürükleyin.</li></ol><div class="info custom-block"><p class="custom-block-title">INFO</p><p>QGroundControl continues to not be signed. You will not to allow permission for it to install based on your macOS version.</p></div><h2 id="ubuntu" tabindex="-1">Ubuntu Linux <a class="header-anchor" href="#ubuntu" aria-label="Permalink to &quot;Ubuntu Linux {#ubuntu}&quot;">​</a></h2><p>Supported versions: Ubuntu 22.04, 24.04:</p><p>Ubuntu, bir seri bağlantı noktasının (veya USB serisinin) robotikle ilgili kullanımına müdahale eden bir seri modem yöneticisi ile birlikte gelir. _ QGroundControl _ &#39;ü kurmadan önce modem yöneticisini kaldırmalı ve seri bağlantı noktasına erişim için kendinize izin vermelisiniz. Ayrıca video akışını desteklemek için _ GStreamer _ &#39;ı da yüklemeniz gerekmektedir.</p><p><strong>Before installing <em>QGroundControl</em> for the first time:</strong></p><ol><li>Enable serial-port access Add your user to the dialout group so you can talk to USB devices without root:</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo usermod -aG dialout &quot;$(id -un)&quot;</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">INFO</p><p>At login, your shell takes a snapshot of your user and group memberships. Because you just changed groups, you need a fresh login shell to pick up “dialout” access. Logging out and back in reloads that snapshot, so you get the new permissions.</p></div><ol><li>(Optional) Disable ModemManager On some Ubuntu-based systems, ModemManager can claim serial ports that QGC needs. If you don&#39;t use it elsewhere, mask or remove it.</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># preferred: stop and mask the service</span></span>
<span class="line"><span>sudo systemctl mask --now ModemManager.service</span></span>
<span class="line"><span></span></span>
<span class="line"><span># or, if you’d rather remove the package</span></span>
<span class="line"><span>sudo apt remove --purge modemmanager</span></span></code></pre></div><ol><li>On the command prompt, enter:</li></ol><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gstreamer1.0-plugins-bad</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gstreamer1.0-libav</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gstreamer1.0-gl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> python3-gi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> python3-gst-1.0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libfuse2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libxcb-xinerama0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libxkbcommon-x11-0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libxcb-cursor-dev</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span></code></pre></div><p><strong>To install <em>QGroundControl</em>:</strong></p><ol><li><p>Download the AppImage for your architecture:</p><ul><li><a href="https://d176tv9ibo4jno.cloudfront.net/builds/master/QGroundControl-x86_64.AppImage" target="_blank" rel="noreferrer">Linux x86_64</a></li><li><a href="https://d176tv9ibo4jno.cloudfront.net/builds/master/QGroundControl-aarch64.AppImage" target="_blank" rel="noreferrer">Linux aarch64</a></li></ul></li><li><p>Make the AppImage executable</p></li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>chmod +x QGroundControl-&lt;arch&gt;.AppImage</span></span></code></pre></div><ol><li>Run QGroundControl Either double-click the AppImage in your file manager or launch it from a terminal:</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>./QGroundControl-&lt;arch&gt;.AppImage</span></span></code></pre></div><h2 id="android" tabindex="-1">Android <a class="header-anchor" href="#android" aria-label="Permalink to &quot;Android {#android}&quot;">​</a></h2><p>Supported versions: Android 9 (API 28) or later (arm 32/64):</p><ul><li><a href="https://d176tv9ibo4jno.cloudfront.net/builds/master/QGroundControl.apk" target="_blank" rel="noreferrer">Android APK</a></li></ul><p>:::important The version of Qt used by QGroundControl requires Android 9 (API 28) as the minimum supported version. It is not possible to support older Android releases. This means that some integrated controllers running older versions of Android are no longer compatible with current builds of QGroundControl. QGroundControl 5.0 stable is the last release that supports these older devices. Note that 5.0 may not fully support firmware versions released after it, so users on older controllers may experience limited compatibility with newer autopilot firmware. :::</p><h2 id="old-stable-releases" tabindex="-1">Old Stable Releases <a class="header-anchor" href="#old-stable-releases" aria-label="Permalink to &quot;Old Stable Releases&quot;">​</a></h2><p>Old stable releases can be found on <a href="https://github.com/mavlink/qgroundcontrol/releases/" target="_blank">GitHub</a>.</p>`,36)]))}const m=a(n,[["render",l]]);export{c as __pageData,m as default};
